        public float this[int i] { get => _data[i]; set => _data[i] = value; }
        public void Resize(int n) { while (_data.Count < n) _data.Add(0f); while (_data.Count > n) _data.RemoveAt(_data.Count - 1); }
        public void Add(float v) => _data.Add(v);
